record.field:
{
    "type": "object",
    "properties": {
        "member_name": {"type": "string", "description": "Name of the member whose belt rank to look up"},
        "member_id": {"type": "integer", "description": "ID of the member whose belt rank to look up"},
        "belt_name": {"type": "string", "description": "Name of a specific belt rank to look up (omit to get member's rank)"}
    }
}

{
    "type": "object",
    "properties": {
        "member_name": {"type": "string", "description": "Name of the member to promote"},
        "member_id": {"type": "integer", "description": "ID of the member"},
        "new_belt": {"type": "string", "description": "Name of the new belt rank"}
    },
    "required": ["member_name", "new_belt"]
}

{
    "type": "object",
    "properties": {
        "member_name": {"type": "string", "description": "Name of the member"},
        "member_id": {"type": "integer", "description": "ID of the member"},
        "target_belt": {"type": "string", "description": "Belt rank they are testing for (e.g. blue belt, green stripe)"},
        "test_date": {"type": "string", "format": "date", "description": "Date of the belt test (YYYY-MM-DD), optional — defaults to the next scheduled test"},
        "test_name": {"type": "string", "description": "Name of the belt test event, optional"}
    },
    "required": ["member_name", "target_belt"]
}

{
    "type": "object",
    "properties": {
        "member_name": {"type": "string", "description": "Name of the member testing"},
        "member_id": {"type": "integer", "description": "ID of the member"},
        "rank_name": {"type": "string", "description": "Name of the belt rank being tested for"},
        "program_name": {"type": "string", "description": "Name of the program"},
        "date_awarded": {"type": "string", "format": "date", "description": "Date awarded (YYYY-MM-DD)"},
        "notes": {"type": "string", "description": "Optional notes"}
    },
    "required": ["member_name", "rank_name"]
}

{
    "type": "object",
    "properties": {
        "name": {"type": "string", "description": "Name of the test event"},
        "test_date": {"type": "string", "format": "date", "description": "Date of the test (YYYY-MM-DD)"},
        "location": {"type": "string", "description": "Location of the test"},
        "program_name": {"type": "string", "description": "Program this test is for"},
        "max_participants": {"type": "integer", "description": "Maximum number of participants", "default": 20}
    },
    "required": ["name", "test_date"]
}

{
    "type": "object",
    "properties": {
        "member_name": {"type": "string", "description": "Name of the member"},
        "test_id": {"type": "integer", "description": "ID of the belt test event"},
        "rank_name": {"type": "string", "description": "Target belt rank"},
        "program_name": {"type": "string", "description": "Name of the program"},
        "notes": {"type": "string", "description": "Optional notes"}
    },
    "required": ["member_name", "test_id"]
}

{
    "type": "object",
    "properties": {
        "belt_color": {"type": "string", "description": "Belt color or rank name (e.g., blue, brown, black)"}
    },
    "required": ["belt_color"]
}

{
    "type": "object",
    "properties": {
        "test_name": {"type": "string", "description": "Name or partial name of the belt test event"},
        "test_id": {"type": "integer", "description": "ID of the belt test event"}
    }
}

{
    "type": "object",
    "properties": {
        "ready_only": {"type": "boolean", "description": "If true, only return members who are ready to test (default false)"}
    }
}
